mapper.select:
SELECT workrecord_id, user_id, nickname, course_name, battle_name, type, is_measure, workrecord_date, distance, max_speed, avg_speed, max_heartrate, avg_heartrate, max_pace, avg_pace, avg_cadence, calorie FROM WORKRECORD_VIEW
AND user_id = #{userId}
AND workrecord_date >= #{startDate}
AND workrecord_date <= #{endDate}
AND type = #{type}
ORDER BY workrecord_id DESC

SELECT SUM(distance) AS sum_distance_all, AVG(avg_speed) AS avg_speed_all, SUM(calorie) AS sum_calorie_all, COUNT(*) AS workrecord_count, AVG(avg_pace) AS avg_pace_all, AVG(avg_cadence) AS avg_cadence_all, AVG(avg_heartrate) AS avg_heartrate_all FROM WORKRECORD_VIEW
AND user_id = #{userId}
AND workrecord_date >= #{startDate}
AND workrecord_date <= #{endDate}
AND type = #{type}
AND battle_name IS NOT NULL
AND (battle_name IS NULL OR battle_name = '')
